const count = (context.get('count') || 0) + 1;
context.set('count', count);

msg.payload = { value: Math.round(Math.random() * 100), run: count };

if (count % 5 === 0) {
    node.error('something went wrong (simulated)', msg);
    return null;
}
return msg;

// msg.report.source is the untouched incident; msg.payload is the rendered report
const inc = msg.report.source;
const s = inc.stats;

const cause = (inc.trigger === 'error' && inc.context && inc.context.error)
    ? String(inc.context.error.message || 'unknown error')
    : inc.trigger;
const from = (inc.context && inc.context.source && inc.context.source.name)
    ? ' in "' + inc.context.source.name + '"'
    : '';

msg.payload = {
    data: {
        title: '✈ Flight Recorder: ' + inc.trigger.toUpperCase() + ' incident',
        message: cause + from + ' — ' + s.recordCount + ' records over the preceding period.'
            + ' Store: ' + inc.storeId + '.'
            + ' Enable file output on the report node for the full timeline.',
        notification_id: 'flight_recorder_' + inc.storeId
    }
};
return msg;
